let aiResponse;
try {
  const inputData = $input.first().json;

  if (inputData.output && Array.isArray(inputData.output)) {
    // Your actual structure: output[0].content[0].text
    const firstOutput = inputData.output[0];
    if (firstOutput && firstOutput.content && firstOutput.content[0] && firstOutput.content[0].text) {
      aiResponse = firstOutput.content[0].text;
    } else {
      throw new Error('output array exists but missing content[0].text');
    }
  } else if (inputData.content && inputData.content.parts && inputData.content.parts[0]) {
    aiResponse = inputData.content.parts[0].text;
  } else if (inputData.message && inputData.message.content && inputData.message.content[0]) {
    aiResponse = inputData.message.content[0].text;
  } else if (inputData.text) {
    aiResponse = inputData.text;
  } else if (typeof inputData === 'string') {
    aiResponse = inputData;
  } else {
    return [{
      json: {
        error: true,
        message: 'Unknown AI response structure',
        rawResponse: JSON.stringify(inputData, null, 2)
      }
    }];
  }
} catch (error) {
  return [{
    json: {
      error: true,
      message: `Error accessing AI response: ${error.message}`,
      rawInput: JSON.stringify($input.first().json, null, 2)
    }
  }];
}

let parsedData;
try {
  let cleanedResponse = aiResponse.trim();

  if (cleanedResponse.startsWith('```json')) {
    cleanedResponse = cleanedResponse.replace(/^```json\n?/, '').replace(/\n?```$/, '');
  } else if (cleanedResponse.startsWith('```')) {
    cleanedResponse = cleanedResponse.replace(/^```\n?/, '').replace(/\n?```$/, '');
  }

  parsedData = JSON.parse(cleanedResponse);
} catch (error) {
  return [{
    json: {
      error: true,
      message: `Failed to parse JSON: ${error.message}`,
      rawResponse: aiResponse
    }
  }];
}

if (!Array.isArray(parsedData)) {
  return [{
    json: {
      error: true,
      message: 'AI response is not an array',
      parsedData: parsedData
    }
  }];
}

